import assert from "node:assert";
import bs58 from "bs58";
import { sha256 } from "@noble/hashes/sha2";
import { hkdf } from "@noble/hashes/hkdf";
import { hmac } from "@noble/hashes/hmac";
import { sha3_256 } from "@noble/hashes/sha3";
import { buildReceivePayload, computeNullifier, deriveDid, validateReceivePayload, } from "../index.js";
function decodeBase58Check(input) {
    const data = bs58.decode(input);
    assert.ok(data.length > 4);
    const payload = data.slice(0, data.length - 4);
    const checksum = data.slice(data.length - 4);
    const expected = sha256(sha256(payload)).slice(0, 4);
    assert.deepStrictEqual(Buffer.from(checksum), Buffer.from(expected));
    return payload;
}
const pk = new Uint8Array(32).fill(0x01);
const did = deriveDid(pk);
assert.ok(did.startsWith("did:comum:"));
const didPayload = decodeBase58Check(did.replace("did:comum:", ""));
const pkHash = sha3_256(pk).slice(0, 20);
assert.deepStrictEqual(Buffer.from(didPayload), Buffer.from(pkHash));
const sk = new Uint8Array(32).fill(0x02);
const id = new Uint8Array(32).fill(0x03);
const info = new TextEncoder().encode("comum-nullifier-v1");
const nk = hkdf(sha3_256, sk, new Uint8Array(), info, 32);
const expectedNullifier = hmac(sha3_256, nk, id);
assert.deepStrictEqual(Buffer.from(computeNullifier(sk, id)), Buffer.from(expectedNullifier));
const of = new Uint8Array(32).fill(0x11);
const payload = buildReceivePayload(of, 1234);
validateReceivePayload(payload);
const ofShort = new Uint8Array(31).fill(0x11);
const badPayload = buildReceivePayload(ofShort, 1234);
assert.throws(() => validateReceivePayload(badPayload));
console.log("comum-js receive ok");
